// nodeID produces a stable short ID from the node name.
func nodeID(name string) string {
	h := sha256.Sum256([]byte(name))
	return fmt.Sprintf("node-%x", h[:4])
}

// projectID produces a stable short ID from the canonical path.
func projectID(path string) string {
	h := sha256.Sum256([]byte(path))
	return fmt.Sprintf("proj-%x", h[:4])
}

// canonicalizePath returns the canonical absolute path, resolving symlinks.
// Falls back to filepath.Abs if symlinks cannot be resolved (e.g. path absent).
func canonicalizePath(path string) string {
	abs, err := filepath.Abs(path)
	if err != nil {
		return path
	}
	resolved, err := filepath.EvalSymlinks(abs)
	if err != nil {
		return abs
	}
	return resolved
}

// resolvedProjectPath canonicalizes path and, if it sits inside a linked git
// worktree, returns the primary worktree root instead. Returns "" only if
// filepath.Abs itself fails (practically impossible).
func resolvedProjectPath(path string) string {
	canonical := canonicalizePath(path)
	if canonical == "" {
		return path
	}

	// Detect linked worktree via git rev-parse.
	gitDirOut, err := runGitCapture(canonical, "rev-parse", "--path-format=absolute", "--git-dir")
	if err != nil {
		return canonical
	}
	gitDir := trimNL(string(gitDirOut))

	commonDirOut, err := runGitCapture(canonical, "rev-parse", "--path-format=absolute", "--git-common-dir")
	if err != nil {
		return canonical
	}
	commonDir := trimNL(string(commonDirOut))

	if gitDir == commonDir {
		// Not a linked worktree.
		return canonical
	}

	// In a linked worktree. Primary worktree is the parent of the shared .git dir.
	if filepath.Base(commonDir) == ".git" {
		return canonicalizePath(filepath.Dir(commonDir))
	}
	// Bare repo: no primary worktree — return canonical path.
	return canonical
}

// resolveGitRemote returns the origin URL for the repo at path, or "".
func resolveGitRemote(path string) string {
	data, err := runGitCapture(path, "remote", "get-url", "origin")
	if err != nil {
		return ""
	}
	return trimNL(string(data))
}

func trimNL(s string) string {
	for len(s) > 0 && (s[len(s)-1] == '\n' || s[len(s)-1] == '\r') {
		s = s[:len(s)-1]
	}
	return s
}

// runGitCapture runs a git command in dir and returns its stdout.
func runGitCapture(dir string, args ...string) ([]byte, error) {
	return internalgit.Command(context.Background(), dir, args...).Output()
}

// PruneResult summarises a PruneStateFile operation so callers can print a
// human-readable summary or write a regression assertion.
type PruneResult struct {
	// StateFile is the absolute path to the state file that was read.

	// /api/projects/{project}/graphql route — per-request reconstruction
	// (LAYER 1) is no longer needed because the resolver reads WorkingDir
	// from the request context.
	gqlOnce    sync.Once
	gqlHandler http.Handler

	// workerIngest is the in-memory derived view of worker reports per
	// ADR-022 rev 5 §Worker-server interface. Workers POST register/event/
	// backfill best-effort; the registry is non-authoritative.
	workerIngest *workerIngestRegistry

	// reportedWorkers adapts workerIngest into the GraphQL reportedWorkers
	// resolver. Held on the Server (rather than constructed lazily) so the
	// ADR-022 step 5c integration test can swap the freshness clock and so
	// every /graphql request shares one instance.
	reportedWorkers *reportedWorkersAdapter
}

// New creates a new DDx server bound to addr, serving data from workingDir.
func New(addr, workingDir string) *Server {
	nodeName := resolveNodeName()
	stateDir := serverAddrDir() // XDG-standard user-level dir, one per node
	state := loadServerState(stateDir, nodeName)
	state.workingDir = workingDir

	workers := NewWorkerManager(workingDir)
	workers.ReconcileStaleWorkers()
	beadHub := bead.NewWatcherHub(250 * time.Millisecond)
	csrfStore, err := ddxgraphql.NewStaticCSRFTokenStore()
	if err != nil {
		// CSRF token generation should never fail outside of a broken
		// crypto/rand. Fall back to a deterministic stub that rejects
		// every request rather than failing open.
		csrfStore = ddxgraphql.NewStaticCSRFTokenStoreWithToken("")
	}
	s := &Server{
		Addr:                               addr,
		WorkingDir:                         workingDir,
		mux:                                http.NewServeMux(),
		startTime:                          time.Now().UTC(),
		workers:                            workers,
		beadHub:                            beadHub,
		state:                              state,
		csrfTokens:                         csrfStore,
		operatorPromptIdempotency:          ddxgraphql.NewMemoryIdempotencyCache(),
		operatorPromptAutoApproveAllowlist: parseOperatorPromptAllowlistEnv(os.Getenv("DDX_OPERATOR_PROMPT_ALLOWLIST")),
		workerIngest:                       newWorkerIngestRegistry(workingDir),
	}
	s.reportedWorkers = newReportedWorkersAdapterWithWorkingDir(s.workerIngest, workingDir)
	state.coordinatorReg = workers.LandCoordinators

	// Register the server's own project immediately.
	state.RegisterProject(workingDir)
	_ = state.save()

	s.routes()
	return s
}

