func TestServerWarnsAboutOrphanHomeServerState(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)

	dir := setupTestDir(t)
	legacyDir := filepath.Join(home, ddxroot.DirName, "server")
	requireNoError(t, os.MkdirAll(legacyDir, 0o755))

	var buf bytes.Buffer
	restore := redirectStdLogger(&buf)
	defer restore()

	_ = New(":0", dir)

	got := buf.String()
	activeRoot := filepath.Join(dir, ddxroot.DirName)
	if !strings.Contains(got, legacyDir) {
		t.Fatalf("expected warning to mention orphaned home server path %s, got %q", legacyDir, got)
	}
	if !strings.Contains(got, activeRoot) {
		t.Fatalf("expected warning to mention active state root %s, got %q", activeRoot, got)
	}
	if !strings.Contains(got, "orphaned") {
		t.Fatalf("expected warning to describe the state as orphaned, got %q", got)
	}
}

