func warnAboutLegacyHomeState(workingDir string) {
	home, err := os.UserHomeDir()
	if err != nil {
		return
	}

	legacy := []struct {
		kind string
		path string
	}{
		{kind: "server", path: ddxroot.JoinHome(home, "server")},
		{kind: "tsnet", path: ddxroot.JoinHome(home, "tsnet")},
	}

	found := make([]struct {
		kind string
		path string
	}, 0, len(legacy))
	for _, entry := range legacy {
		info, statErr := os.Stat(entry.path)
		if statErr != nil || !info.IsDir() {
			continue
		}
		found = append(found, entry)
	}
	if len(found) == 0 {
		return
	}

	activeRoot := activeProjectStateRootForWarning(workingDir)
	for _, entry := range found {
		log.Printf(
			"ddx-server: legacy home %s state at %s is orphaned; active project state root is %s; remove or migrate the stale directory intentionally",
			entry.kind, entry.path, activeRoot,
		)
	}
}

func activeProjectStateRootForWarning(projectRoot string) string {
	inTreeRoot := filepath.Join(projectRoot, ddxroot.DirName)
	if info, err := os.Stat(filepath.Join(inTreeRoot, "config.yaml")); err == nil && !info.IsDir() {
		return inTreeRoot
	}
	return filepath.Join(xdgDataHomeForWarning(), "ddx", "projects", projectIdentityForWarning(projectRoot))
}

func xdgDataHomeForWarning() string {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return xdg
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return filepath.Join(os.TempDir(), "ddx-xdg")
	}
	return filepath.Join(home, ".local", "share")
}

func projectIdentityForWarning(projectRoot string) string {
	return projectIdentityFromRemoteForWarning(projectRoot, resolveGitRemote(projectRoot))
}

func projectIdentityFromRemoteForWarning(projectRoot, remoteURL string) string {
	if remoteProject, ok := parseRemoteProjectForWarning(remoteURL); ok {
		return remoteProject
	}
	return localProjectIdentityForWarning(projectRoot)
}

func parseRemoteProjectForWarning(remoteURL string) (string, bool) {
	remoteURL = strings.TrimSpace(remoteURL)
	if remoteURL == "" {
		return "", false
	}
	if host, repoPath, ok := parseSCPLikeRemoteForWarning(remoteURL); ok {
		return filepath.Join(host, repoPath), true
	}
	u, err := url.Parse(remoteURL)
	if err != nil || u.Host == "" {
		return "", false
	}
	repoPath := normalizeRepoPathForWarning(u.Path)
	if repoPath == "" {
		return "", false
	}
	return filepath.Join(u.Host, repoPath), true
}

func parseSCPLikeRemoteForWarning(remoteURL string) (host, repoPath string, ok bool) {
	if strings.Contains(remoteURL, "://") {
		return "", "", false
	}
	at := strings.IndexByte(remoteURL, '@')
	colon := strings.IndexByte(remoteURL, ':')
	if at <= 0 || colon <= at+1 {
		return "", "", false
	}
	host = strings.TrimSpace(remoteURL[at+1 : colon])
	repoPath = normalizeRepoPathForWarning(remoteURL[colon+1:])
	if host == "" || repoPath == "" {
		return "", "", false
	}
	return host, repoPath, true
}

